from azure.ai.projects import AgentClient
from datetime import datetime, timedelta

def detect_bing_freshness(agent_response):
    client = AgentClient.from_connection_string('your-connection-string')

    # Extract grounding sources from agent trace
    trace = client.get_agent_trace(agent_response.trace_id)
    bing_sources = [tool for tool in trace.tools if tool.type == 'bing_search']

    for source in bing_sources:
        pub_date = datetime.fromisoformat(source.metadata.get('published_date'))
        if datetime.now() - pub_date > timedelta(days=7):
            return {
                'hallucination': True,
                'type': 'outdated_grounding',
                'confidence': 0.92,
                'evidence': f"Bing source {source.url} older than 7 days"
            }
    return {'hallucination': False}

from azure.ai.projects import AgentClient
import re

def detect_file_metadata_pollution(agent_response):
    metadata_pattern = re.compile(r'(LastModified|Content-MD5|Etag|Content-Type):')

    if metadata_pattern.search(agent_response.content):
        return {
            'hallucination': True,
            'type': 'metadata_pollution',
            'confidence': 0.88,
            'evidence': 'Azure blob metadata detected in response content',
            'suggestion': 'Use content extraction transform'
        }
    return {'hallucination': False}

