from azure.ai.projects import AgentClient
from datetime import datetime, timedelta

def freshness_filter_middleware(request):
    client = AgentClient.from_connection_string('your-connection-string')

    # Intercept Bing tool calls
    if request.tools and any(t.type == 'bing_search' for t in request.tools):
        fresh_results = []
        for result in request.tools[0].results:
            pub_date = datetime.fromisoformat(result.metadata['published_date'])
            if datetime.now() - pub_date <= timedelta(days=3):
                fresh_results.append(result)

        if len(fresh_results) == 0:
            request.tools[0].results = [{'content': 'No recent sources found. Using cached enterprise knowledge base.', 'fresh': False}]
        else:
            request.tools[0].results = fresh_results

    return request
